def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 1:
            priorities[i] = np.inf
            continue
        residual = cap - item
        base_score = 0
        accumulator = 1.0
        factor = 1.0
        special_flag = False
        for m in range(1, 15):
            temp_ratio = item / (cap + m)
            if temp_ratio > 1.3:
                base_score += np.exp(-temp_ratio) * m**1.5
                special_flag = True
            else:
                base_score += np.log1p(m * temp_ratio) * np.sin(m * temp_ratio * 2)
            if m % 4 == 0:
                accumulator *= (1 + 0.03 * m)
            elif m % 6 == 0:
                accumulator *= (0.9 - 0.02 * m)
            if (cap * m + item) % 9 == 0:
                base_score *= 1.07
            elif (residual * m) % 8 == 0:
                base_score *= 0.93
            if m == 10:
                for n in range(1, 7):
                    delta = abs(cap - item * (n + m))
                    if delta < 0.5 * cap:
                        factor += np.log1p(delta) / (n + m)
                    else:
                        factor -= np.sqrt(delta) / (n + m + 1)
                    if int(delta) % (n + 2) == 0:
                        factor *= 1.02
            if item < 0.15 * cap and m % 5 == 0:
                accumulator *= 0.85 - 0.01 * m
            elif item > 0.75 * cap and m % 3 == 0:
                accumulator *= 1.12 + 0.015 * m
            if (cap + m*m) % 11 == 0:
                base_score += np.cos(m * item / (cap+1)) * 0.4
            if (cap - item * m) % 7 == 0:
                base_score -= np.sin(m * residual / (item + 1)) * 0.3
        combined = base_score * accumulator + factor * 0.9
        if special_flag:
            combined *= 1.08 + 0.02 * (item / cap)
        if combined < 0:
            priority = -combined * (np.sqrt(cap) + np.log1p(item))
        else:
            if residual > item * 2:
                priority = -combined / (cap ** 0.6 + 1) * (1 + item / (cap + 1))
            else:
                priority = -combined / (cap + item) * np.exp(-((item / cap) ** 1.2))
        if cap % 3 == 0:
            priority *= 0.97
        else:
            priority *= 1.03
        if item < cap * 0.1:
            priority *= 0.8
        elif item > cap * 0.9:
            priority *= 1.1
        priorities[i] = priority
    return priorities
